-- primary=semantic_campaign × cross=semantic_order — blended whole-period, joined on (brand_id, currency_code).
-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_cac_all AS
WITH unioned AS (
  SELECT
    brand_id,
    currency_code,
    'base' AS __src,
    spend_minor AS spend_minor,
    NULL AS is_new_customer,
    NULL AS brain_id
  FROM iceberg.brain_serving.semantic_campaign
  UNION ALL
  SELECT
    brand_id,
    currency_code,
    'cross' AS __src,
    NULL AS spend_minor,
    is_new_customer AS is_new_customer,
    brain_id AS brain_id
  FROM iceberg.brain_serving.semantic_order
),
agg AS (
  SELECT
    brand_id,
    currency_code,
    SUM(spend_minor) FILTER (WHERE __src = 'base') AS spend_minor,
    COUNT(DISTINCT CASE WHEN is_new_customer THEN brain_id END) FILTER (WHERE __src = 'cross') AS new_customers
  FROM unioned
  WHERE ${BRAND_PREDICATE}
  GROUP BY 1, 2
)
SELECT
  brand_id,
  currency_code,
  spend_minor,
  new_customers,
  (spend_minor / NULLIF(new_customers, 0)) AS cac
FROM agg;
